"""SQLAlchemy ORM models — generated by doql."""
from sqlalchemy import Column, String, Integer, Float, Boolean, Text, Date, DateTime, JSON, ForeignKey
from sqlalchemy.orm import relationship
from database import Base


class Post(Base):
    __tablename__ = "posts"

    id = Column(String(36), primary_key=True)
    title = Column(String(255))
    slug = Column(String(255), unique=True)
    content = Column(Text)
    excerpt = Column(Text, nullable=True)
    author = Column(String(255))
    category = Column(String(255), nullable=True)
    tags = Column(JSON, nullable=True)
    featured_image = Column(String(255), nullable=True)
    published_at = Column(DateTime, nullable=True)
    created = Column(DateTime, nullable=True)
    updated = Column(DateTime, nullable=True)


class Author(Base):
    __tablename__ = "authors"

    id = Column(String(36), primary_key=True)
    name = Column(String(255))
    email = Column(String(255), unique=True)
    bio = Column(Text, nullable=True)
    avatar = Column(String(255), nullable=True)
    created = Column(DateTime, nullable=True)


class Category(Base):
    __tablename__ = "categorys"

    id = Column(String(36), primary_key=True)
    name = Column(String(255), unique=True)
    slug = Column(String(255), unique=True)
    description = Column(Text, nullable=True)
    parent = Column(String(255), nullable=True)
    sort_order = Column(Integer, nullable=True, default=0)


class Comment(Base):
    __tablename__ = "comments"

    id = Column(String(36), primary_key=True)
    post = Column(String(255))
    author_name = Column(String(255))
    author_email = Column(String(255))
    content = Column(Text)
    approved = Column(Boolean, nullable=True, default=False)
    parent = Column(String(255), nullable=True)
    created = Column(DateTime, nullable=True)


class MediaFile(Base):
    __tablename__ = "media_files"

    id = Column(String(36), primary_key=True)
    filename = Column(String(255))
    mime_type = Column(String(255))
    size = Column(Integer)
    url = Column(String(255))
    alt_text = Column(String(255), nullable=True)
    uploaded_by = Column(String(255), nullable=True)
    created = Column(DateTime, nullable=True)
